## File 1: `apps/web/lib/stores/dashboard-store.ts`

Follow the exact pattern from `sidebar-store.ts` (Zustand + persist).

```typescript
import { create } from 'zustand';
import { persist } from 'zustand/middleware';

interface DashboardStore {
  // Preferences
  collapsedSections: string[];    // section IDs: 'brief', 'timeline', 'alerts', 'status'
  dismissedAlertIds: number[];    // alert IDs dismissed by user
  autoRefresh: boolean;           // default: true
  refreshInterval: number;        // default: 300_000 (5 min)
  timelineFilter: string | null;  // event_type filter or null for all

  // Actions
  toggleSection: (section: string) => void;
  dismissAlert: (alertId: number) => void;
  undismissAlert: (alertId: number) => void;
  clearDismissedAlerts: () => void;
  setAutoRefresh: (enabled: boolean) => void;
  setRefreshInterval: (ms: number) => void;
  setTimelineFilter: (filter: string | null) => void;
}

export const useDashboardStore = create<DashboardStore>()(
  persist(
    (set) => ({
      collapsedSections: [],
      dismissedAlertIds: [],
      autoRefresh: true,
      refreshInterval: 300_000,
      timelineFilter: null,

      toggleSection: (section) =>
        set((s) => ({
          collapsedSections: s.collapsedSections.includes(section)
            ? s.collapsedSections.filter((id) => id !== section)
            : [...s.collapsedSections, section],
        })),

      dismissAlert: (alertId) =>
        set((s) => ({
          dismissedAlertIds: [...s.dismissedAlertIds, alertId],
        })),

      undismissAlert: (alertId) =>
        set((s) => ({
          dismissedAlertIds: s.dismissedAlertIds.filter((id) => id !== alertId),
        })),

      clearDismissedAlerts: () => set({ dismissedAlertIds: [] }),

      setAutoRefresh: (enabled) => set({ autoRefresh: enabled }),
      setRefreshInterval: (ms) => set({ refreshInterval: ms }),
      setTimelineFilter: (filter) => set({ timelineFilter: filter }),
    }),
    { name: 'gilbertus-dashboard' },
  ),
);
```

## File 2: `apps/web/lib/hooks/use-dashboard.ts`

TanStack Query hooks for all dashboard data. The app already has a QueryClientProvider in the root layout (from P1), so useQuery is available.

```typescript
import { useQuery } from '@tanstack/react-query';
import {
  fetchBrief,
  fetchAlerts,
  fetchStatus,
  fetchTimeline,
  fetchCommitments,
  fetchBudget,
} from '@gilbertus/api-client';
import type {
  MorningBriefResponse,
  AlertsResponse,
  StatusResponse,
  TimelineResponse,
  CommitmentsListResponse,
  BudgetResponse,
} from '@gilbertus/api-client';
import { useDashboardStore } from '../stores/dashboard-store';

export function useBrief(options?: { force?: boolean; date?: string }) {
  const { autoRefresh, refreshInterval } = useDashboardStore();
  return useQuery<MorningBriefResponse>({
    queryKey: ['brief', options?.date ?? 'today'],
    queryFn: () => fetchBrief({ force: options?.force, date: options?.date }),
    refetchInterval: autoRefresh ? refreshInterval : false,
  });
}

export function useAlerts(options?: { activeOnly?: boolean; severity?: string }) {
  const { autoRefresh } = useDashboardStore();
  return useQuery<AlertsResponse>({
    queryKey: ['alerts', options?.activeOnly, options?.severity],
    queryFn: () => fetchAlerts({
      active_only: options?.activeOnly ?? true,
      severity: options?.severity,
    }),
    refetchInterval: autoRefresh ? 60_000 : false,  // 60s for alerts
  });
}

export function useStatus() {
  const { autoRefresh } = useDashboardStore();
  return useQuery<StatusResponse>({
    queryKey: ['status'],
    queryFn: fetchStatus,
    refetchInterval: autoRefresh ? 60_000 : false,
  });
}

export function useTimeline(options?: { eventType?: string; limit?: number }) {
  const { autoRefresh, refreshInterval, timelineFilter } = useDashboardStore();
  const filter = options?.eventType ?? timelineFilter;
  return useQuery<TimelineResponse>({
    queryKey: ['timeline', filter, options?.limit],
    queryFn: () => fetchTimeline({
      event_type: filter ?? undefined,
      limit: options?.limit ?? 20,
    }),
    refetchInterval: autoRefresh ? refreshInterval : false,
  });
}

export function useCommitmentsCount() {
  const { autoRefresh, refreshInterval } = useDashboardStore();
  return useQuery<CommitmentsListResponse>({
    queryKey: ['commitments', 'open'],
    queryFn: () => fetchCommitments({ status: 'open' }),
    refetchInterval: autoRefresh ? refreshInterval : false,
  });
}

export function useBudget() {
  const { autoRefresh, refreshInterval } = useDashboardStore();
  return useQuery<BudgetResponse>({
    queryKey: ['budget'],
    queryFn: fetchBudget,
    refetchInterval: autoRefresh ? refreshInterval : false,
  });
}

// Lightweight hook for notification bell — polls every 60s
export function useAlertsBell() {
  return useQuery<AlertsResponse>({
    queryKey: ['alerts', 'bell'],
    queryFn: () => fetchAlerts({ active_only: true, limit: 5 }),
    refetchInterval: 60_000,
  });
}
```

IMPORTANT: Import all API functions and types from `@gilbertus/api-client` (created in P2T1). The QueryClientProvider is already configured in the app layout from Part 1.

